import React, { useState, useEffect, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import KycUpload from './KycUpload';
import ChangePassword from './ChangePassword';
import Deposit from './Deposit';
import Withdraw from './Withdraw';
import TransactionHistory from './TransactionHistory';

const Dashboard = () => {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [activeTab, setActiveTab] = useState('overview');
  const navigate = useNavigate();

  const loadProfile = useCallback(async () => {
    const token = localStorage.getItem('token');
    if (!token) {
      navigate('/login');
      return;
    }
    try {
      const res = await axios.get('http://localhost:5000/api/auth/profile', {
        headers: { Authorization: `Bearer ${token}` }
      });
      setUser(res.data);
    } catch (err) {
      setError('Unable to load profile. Please login again.');
      localStorage.removeItem('token');
      navigate('/login');
    } finally {
      setLoading(false);
    }
  }, [navigate]);

  useEffect(() => {
    loadProfile();
  }, [loadProfile]);

  const handleBalanceUpdate = (newBalance) => {
    setUser(prev => ({ ...prev, balance: newBalance }));
  };

  if (loading) return <div className="page-content"><div className="card">Loading dashboard...</div></div>;
  if (error) return <div className="page-content"><div className="card error">{error}</div></div>;

  return (
    <div className="dashboard-layout">
      {/* Sidebar */}
      <aside className="dashboard-sidebar">
        <div className="sidebar-user">
          <div className="user-avatar">{user?.username?.charAt(0).toUpperCase()}</div>
          <div className="user-info">
            <h4>{user?.username}</h4>
            <p>{user?.email}</p>
          </div>
        </div>

        <nav className="sidebar-nav">
          <button 
            className={`nav-item ${activeTab === 'overview' ? 'active' : ''}`}
            onClick={() => setActiveTab('overview')}
          >
            <span className="icon overview"></span> Overview
          </button>
          <button 
            className={`nav-item ${activeTab === 'deposit' ? 'active' : ''}`}
            onClick={() => setActiveTab('deposit')}
          >
            <span className="icon deposit"></span> Deposit
          </button>
          <button 
            className={`nav-item ${activeTab === 'withdraw' ? 'active' : ''}`}
            onClick={() => setActiveTab('withdraw')}
          >
            <span className="icon withdraw"></span> Withdraw
          </button>
          <button 
            className={`nav-item ${activeTab === 'kyc' ? 'active' : ''}`}
            onClick={() => setActiveTab('kyc')}
          >
            <span className="icon kyc"></span> KYC
          </button>
          <button 
            className={`nav-item ${activeTab === 'security' ? 'active' : ''}`}
            onClick={() => setActiveTab('security')}
          >
            <span className="icon security"></span> Security
          </button>
          <button 
            className={`nav-item ${activeTab === 'transactions' ? 'active' : ''}`}
            onClick={() => setActiveTab('transactions')}
          >
            <span className="icon transactions"></span> Transactions
          </button>
        </nav>

        <div className="sidebar-footer">
          <button className="btn-logout" onClick={() => {
            localStorage.removeItem('token');
            navigate('/login');
          }}>Logout</button>
        </div>
      </aside>

      {/* Main Content */}
      <main className="dashboard-main">
        {activeTab === 'overview' && (
          <div className="content-section">
            <h2>Account Overview</h2>
            <div className="balance-display">
              <div className="balance-card-large">
                <div className="balance-label">Total Balance</div>
                <div className="balance-amount">${user.balance.toFixed(2)}</div>
                <div className="balance-info">
                  <div className="info-item">
                    <span className="label">KYC Status:</span>
                    <span className={`status ${user.isKycVerified ? 'verified' : 'pending'}`}>
                      {user.isKycVerified ? '✓ Verified' : '⏳ Pending'}
                    </span>
                  </div>
                  <div className="info-item">
                    <span className="label">Documents:</span>
                    <span>{user.kycDocuments?.length || 0} uploaded</span>
                  </div>
                </div>
              </div>
            </div>
          </div>
        )}

        {activeTab === 'deposit' && (
          <div className="content-section">
            <h2>Add Funds</h2>
            <Deposit onDepositSuccess={handleBalanceUpdate} />
          </div>
        )}

        {activeTab === 'withdraw' && (
          <div className="content-section">
            <h2>Withdraw Funds</h2>
            <Withdraw onWithdrawSuccess={handleBalanceUpdate} />
          </div>
        )}

        {activeTab === 'kyc' && (
          <div className="content-section">
            <h2>KYC Documents</h2>
            <KycUpload onSuccess={loadProfile} />
          </div>
        )}

        {activeTab === 'security' && (
          <div className="content-section">
            <h2>Security Settings</h2>
            <ChangePassword />
          </div>
        )}

        {activeTab === 'transactions' && (
          <div className="content-section">
            <h2>Transaction History</h2>
            <TransactionHistory />
          </div>
        )}
      </main>
    </div>
  );
};

export default Dashboard;
